// Decode base64 naar hex
const base64 = msg.payload;
const buffer = Buffer.from(base64, 'base64');
const hex = buffer.toString('hex');

// Stel productType in
msg.productType = "pulse";

// Overschrijf payload met hex-string
msg.payload = hex;

return msg;

// Haal globale MID op
let mid = global.get("mid") || 0;

// Device ID handmatig of via msg.DevEUI
const Dev = "ASSET_ID_START_MET_36";

// Mapping: kanaal → ID
const channelTypeMapping = {
    A: 5000, // water
    B: null, // niet gebruikt
};

// Extra ID-mapping
const statusIdMapping = {
    batteryTextStatus: 7100 // LOW / GOOD
};

// Input ophalen
const input = msg.payload;
const result = {
    MID: mid,
    D: [
        {
            Dev: Dev,
            TS: new Date(input.timestamp || Date.now()).toISOString(),
            ED: [],
            MD: []
        }
    ]
};

// Vul MD-array met counterValues
if (
    input &&
    Array.isArray(input.counterValues) &&
    input.counterValues.length === 2
) {
    ["A", "B"].forEach((channel, index) => {
        const id = channelTypeMapping[channel];
        const val = input.counterValues[index];

        if (id === undefined || id === null) return;

        if (typeof val === "number") {
            let finalVal = parseFloat(val);

            // water channel A: divide by 1000
            if (channel === "A") {
                finalVal = finalVal / 1000;
            }

            result.D[0].MD.push({
                Id: id,
                Val: finalVal
            });
        }
    });
} else {
    node.warn("Geen geldige counterValues gevonden in msg.payload");
}

// ✅ Voeg batterijstatus toe als event (ED)
if (input?.status?.lowBattery !== undefined) {
    const val = input.status.lowBattery ? "LOW" : "GOOD";
    result.D[0].ED.push({
        Id: statusIdMapping.batteryTextStatus, // = 7100
        Val: val,
        Sev: 2
    });
}


// MID ophogen
global.set("mid", mid + 1);

// Zet als payload
msg.payload = result;
return msg;
